#include "primer/hyperloglog.h"

#include <cmath>
#include <iomanip>

namespace bustub {

template <typename KeyType>
HyperLogLog<KeyType>::HyperLogLog(int16_t n_bits) : n_bits_(n_bits), cardinality_(0) {
  // Handle edge cases where n_bits <= 0
  if (n_bits_ <= 0) {
    n_bits_ = 0;
    registers_.clear();
  } else {
    // Number of registers is 2^n_bits
    size_t num_registers = 1ULL << n_bits_;
    registers_.assign(num_registers, 0);
  }
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<BITSET_CAPACITY> {
  return std::bitset<BITSET_CAPACITY>(hash);
}

template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<BITSET_CAPACITY> &bset) const -> uint64_t {
  // Find the position of the leftmost 1-bit (counting from left, starting at 1)
  // If no 1-bit found, return BITSET_CAPACITY + 1
  for (uint64_t i = 0; i < BITSET_CAPACITY; ++i) {
    if (bset[BITSET_CAPACITY - 1 - i]) {
      return i + 1;
    }
  }
  return BITSET_CAPACITY + 1;
}

template <typename KeyType>
auto HyperLogLog<KeyType>::AddElem(KeyType val) -> void {
  if (n_bits_ <= 0) {
    return;
  }

  // Hash the element
  hash_t hash = CalculateHash(val);

  // Convert hash to binary
  auto binary = ComputeBinary(hash);

  // Extract the register index from the first n_bits
  uint64_t register_idx = 0;
  for (int16_t i = 0; i < n_bits_; ++i) {
    if (binary[BITSET_CAPACITY - 1 - i]) {
      register_idx |= (1ULL << (n_bits_ - 1 - i));
    }
  }

  // Extract the remaining bits and find the position of the leftmost 1
  std::bitset<BITSET_CAPACITY> remaining_bits;
  for (int16_t i = n_bits_; i < BITSET_CAPACITY; ++i) {
    if (binary[BITSET_CAPACITY - 1 - i]) {
      remaining_bits[BITSET_CAPACITY - 1 - (i - n_bits_)] = 1;
    }
  }

  uint64_t position = PositionOfLeftmostOne(remaining_bits);

  // Update the register with the max value
  {
    std::lock_guard<std::mutex> guard(lock_);
    registers_[register_idx] = std::max(registers_[register_idx], static_cast<uint8_t>(position));
  }
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeCardinality() -> void {
  std::lock_guard<std::mutex> guard(lock_);

  if (n_bits_ <= 0) {
    cardinality_ = 0;
    return;
  }

  size_t num_registers = 1ULL << n_bits_;
  double sum = 0.0;

  for (size_t i = 0; i < num_registers; ++i) {
    sum += std::pow(2.0, -static_cast<double>(registers_[i]));
  }

  // E = CONSTANT * m^2 / sum, where m = 2^n_bits
  double m = static_cast<double>(num_registers);
  double estimate = CONSTANT * m * m / sum;

  cardinality_ = static_cast<size_t>(std::round(estimate));
}

