#include "primer/hyperloglog_presto.h"

#include <cmath>

namespace bustub {

template <typename KeyType>
HyperLogLogPresto<KeyType>::HyperLogLogPresto(int16_t n_leading_bits)
    : n_leading_bits_(n_leading_bits), cardinality_(0) {
  if (n_leading_bits_ < 0) {
    n_leading_bits_ = 0;
    dense_bucket_.clear();
    overflow_bucket_.clear();
  } else {
    // Number of registers is 2^n_leading_bits (even for 0, this is 1)
    size_t num_registers = 1ULL << n_leading_bits_;
    dense_bucket_.assign(num_registers, 0);
  }
}

template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (n_leading_bits_ < 0 || dense_bucket_.empty()) {
    return;
  }

  hash_t hash = CalculateHash(val);

  // Extract register index from the first n_leading_bits
  uint64_t register_idx = hash & ((1ULL << n_leading_bits_) - 1);

  // Get the remaining bits
  hash_t w = hash >> n_leading_bits_;

  // Find the position of the leftmost 1-bit (rho + 1)
  uint64_t position = 0;
  if (w == 0) {
    // No 1-bit found, position is the maximum
    position = 64 - n_leading_bits_ + 1;
  } else {
    // Find the position of the first 1-bit from the right
    position = __builtin_ctzll(w) + 1;
  }

  // Update register with max value using split encoding
  {
    std::lock_guard<std::mutex> guard(lock_);

    uint64_t dense_val = position & ((1ULL << DENSE_BUCKET_SIZE) - 1);
    uint64_t overflow_val = position >> DENSE_BUCKET_SIZE;

    // Get current stored values
    uint64_t current_dense = dense_bucket_[register_idx].to_ullong();
    uint64_t current_overflow = 0;
    if (overflow_bucket_.find(register_idx) != overflow_bucket_.end()) {
      current_overflow = overflow_bucket_[register_idx].to_ullong();
    }

    // Reconstruct full values
    uint64_t current_position = (current_overflow << DENSE_BUCKET_SIZE) | current_dense;

    // Update if new position is larger
    if (position > current_position) {
      dense_bucket_[register_idx] = dense_val;
      if (overflow_val > 0) {
        overflow_bucket_[register_idx] = overflow_val;
      } else {
        overflow_bucket_.erase(register_idx);
      }
    }
  }
}

template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  std::lock_guard<std::mutex> guard(lock_);

  if (n_leading_bits_ <= 0) {
    cardinality_ = 0;
    return;
  }

  size_t num_registers = 1ULL << n_leading_bits_;
  double sum = 0.0;

  for (size_t i = 0; i < num_registers; ++i) {
    uint64_t dense_val = dense_bucket_[i].to_ullong();
    uint64_t overflow_val = 0;

    if (overflow_bucket_.find(i) != overflow_bucket_.end()) {
      overflow_val = overflow_bucket_[i].to_ullong();
    }

    // Reconstruct the full position value
    uint64_t position = (overflow_val << DENSE_BUCKET_SIZE) | dense_val;

    sum += std::pow(2.0, -static_cast<double>(position));
  }

  // E = CONSTANT * m^2 / sum, where m = 2^n_leading_bits
  double m = static_cast<double>(num_registers);
  double estimate = CONSTANT * m * m / sum;

  cardinality_ = static_cast<uint64_t>(estimate);
}

